from cryptography.fernet import Fernet

def generate_key():
    return Fernet.generate_key()

def encrypt_card_number(card_number, key):
    f = Fernet(key)
    encrypted_number = f.encrypt(card_number.encode())
    return encrypted_number.decode()

def decrypt_card_number(encrypted_number, key):
    f = Fernet(key)
    decrypted_number = f.decrypt(encrypted_number.encode())
    return decrypted_number.decode()